     1→import {
     2→	buildMultiFilePrompt,
     3→	buildSingleFilePrompt,
     4→	estimateTokens,
     5→	type FileContext,
     6→} from "@shared/claude/prompt-builder";
     7→import {
     8→	parseEvaluatorResult,
     9→	populateCrossFileSnippets,
    10→	populateSnippets,
    11→	separateIssuesByType,
    12→} from "@shared/claude/response-parser";
    13→import { DEFAULT_TIMEOUT_MS } from "@shared/constants";
    14→import { getProvider, type IAIProvider } from "@shared/providers";
    15→import type {
    16→	EvaluatorFilter,
    17→	Issue,
    18→	StructuredError,
    19→	Usage,
    20→} from "@shared/types/evaluation";
    21→import { getIssueSeverity } from "@shared/types/evaluation";
    22→import { determineErrorCategory } from "@shared/utils/error-categorizer";
    23→import { createLogger, runnerLogger } from "@shared/utils/logger";
    24→import { readFile, writeFile } from "fs/promises";
    25→import { basename, dirname, resolve } from "path";
    26→import { fileURLToPath } from "url";
    27→import {
    28→	filterFilesForEvaluator,
    29→	getFilteringReason,
    30→	hasFileFiltering,
    31→} from "./config";
    32→import {
    33→	filterEvaluatorsByIds,
    34→	filterEvaluatorsByType,
    35→	getIssueTypeFromEvaluatorName,
    36→	shouldExecuteIfNoFile,
    37→} from "./evaluator-types";
    38→import { logRuntimePrompt } from "./runtime-prompt-logger";
    39→
    40→/**
    41→ * Format token usage with cache breakdown
    42→ */
    43→function formatTokenUsage(usage: Usage): string {
    44→	const cacheRead = usage.cache_read_input_tokens || 0;
    45→	const cacheWrite = usage.cache_creation_input_tokens || 0;
    46→	const totalInput = usage.input_tokens + cacheRead + cacheWrite;
    47→	const parts = [`Input: ${totalInput}`];
    48→	if (cacheRead > 0 || cacheWrite > 0) {
    49→		parts[0] += ` (${usage.input_tokens} new, ${cacheRead} cache read, ${cacheWrite} cache write)`;
    50→	}
    51→	parts.push(`Output: ${usage.output_tokens}`);
    52→	return `Token usage - ${parts.join(", ")}`;
    53→}
    54→
    55→// Try to import embedded prompts (available in single binary mode)
    56→let embeddedEvaluatorPrompts: Record<string, string> | null = null;
    57→try {
    58→	const embedded = await import("../../embedded/prompts-assets");
    59→	embeddedEvaluatorPrompts = embedded.evaluatorPrompts;
    60→} catch {
    61→	// Not in embedded mode, will use file-based prompts
    62→}
    63→
    64→// Get the directory where evaluator prompts are stored (file-based fallback)
    65→const __dirname = dirname(fileURLToPath(import.meta.url));
    66→const EVALUATORS_DIR = resolve(__dirname, "../../../prompts/evaluators");
    67→
    68→/**
    69→ * Load evaluator prompt content, using embedded if available
    70→ */
    71→async function loadEvaluatorPrompt(evaluatorPath: string): Promise<string> {
    72→	// Extract evaluator ID from path (e.g., "content-quality" from "content-quality.md")
    73→	const filename = basename(evaluatorPath);
    74→	const evaluatorId = filename.replace(".md", "");
    75→
    76→	// Try embedded prompts first
    77→	if (embeddedEvaluatorPrompts && embeddedEvaluatorPrompts[evaluatorId]) {
    78→		return embeddedEvaluatorPrompts[evaluatorId];
    79→	}
    80→
    81→	// Fall back to file-based prompts
    82→	return readFile(evaluatorPath, "utf-8");
    83→}
    84→
    85→/**
    86→ * List of evaluators in order
    87→ */
    88→export const EVALUATOR_FILES = [
    89→	"content-quality.md",
    90→	"structure-formatting.md",
    91→	"command-completeness.md",
    92→	"testing-validation.md",
    93→	"code-style.md",
    94→	"language-clarity.md",
    95→	"git-workflow.md",
    96→	"project-structure.md",
    97→	"security.md",
    98→	"completeness.md",
    99→	"subdirectory-coverage.md",
   100→	"context-gaps.md",
   101→	"contradictory-instructions.md",
   102→	"test-patterns-coverage.md",
   103→	"database-patterns-coverage.md",
   104→	"markdown-validity.md",
   105→	"outdated-documentation.md",
   106→] as const;
   107→
   108→export interface EvaluatorResult {
   109→	evaluator: string;
   110→	issues: Issue[];
   111→	error?: string;
   112→	errors?: StructuredError[]; // Structured error information
   113→	usage?: Usage;
   114→	cost_usd?: number;
   115→	duration_ms?: number;
   116→	finalPrompt?: string;
   117→	/** Whether this evaluator was skipped (e.g., no file mode) */
   118→	skipped?: boolean;
   119→	/** Reason why this evaluator was skipped */
   120→	skipReason?: string;
   121→}
   122→
   123→export interface FileEvaluationResult {
   124→	filePath: string;
   125→	relativePath: string;
   126→	evaluations: EvaluatorResult[];
   127→	totalIssues: number;
   128→	highCount: number;
   129→	mediumCount: number;
   130→	lowCount: number;
   131→	totalUsage?: Usage;
   132→	totalCost?: number;
   133→	totalDuration?: number;
   134→}
   135→
   136→/**
   137→ * Run evaluators with concurrency limit to avoid overwhelming the system
   138→ */
   139→async function runWithConcurrencyLimit<T, R>(
   140→	items: T[],
   141→	limit: number,
   142→	fn: (item: T, index: number) => Promise<R>,
   143→): Promise<R[]> {
   144→	const results: R[] = new Array(items.length); // Pre-allocate array
   145→	let activeCount = 0;
   146→	let currentIndex = 0;
   147→
   148→	return new Promise((resolve) => {
   149→		const runNext = () => {
   150→			if (currentIndex >= items.length && activeCount === 0) {
   151→				resolve(results);
   152→				return;
   153→			}
   154→
   155→			while (activeCount < limit && currentIndex < items.length) {
   156→				const index = currentIndex++;
   157→				const item = items[index];
   158→
   159→				// Validate item exists
   160→				if (item === undefined) {
   161→					runnerLogger.error(`Item at index ${index} is undefined, skipping`);
   162→					results[index] = new Error("Item undefined") as R;
   163→					continue;
   164→				}
   165→
   166→				activeCount++;
   167→
   168→				fn(item, index)
   169→					.then((result) => {
   170→						results[index] = result;
   171→					})
   172→					.catch((error) => {
   173→						runnerLogger.error(`Task ${index} failed:`, error);
   174→						results[index] = error;
   175→					})
   176→					.finally(() => {
   177→						activeCount--;
   178→						runNext();
   179→					});
   180→			}
   181→		};
   182→
   183→		runNext();
   184→	});
   185→}
   186→
   187→/**
   188→ * Run all evaluators against a single context file (AGENTS.md or CLAUDE.md) with controlled concurrency
   189→ */
   190→export async function runAllEvaluators(
   191→	agentsFilePath: string,
   192→	options: {
   193→		verbose?: boolean;
   194→		debug?: boolean;
   195→		debugDir?: string;
   196→		concurrency?: number;
   197→		evaluators?: number;
   198→		baseDir?: string;
   199→		projectContext?: string;
   200→		onProgress?: (evaluator: string, index: number, total: number) => void;
   201→		/** Callback for retry events */
   202→		onRetry?: (
   203→			evaluator: string,
   204→			attempt: number,
   205→			maxRetries: number,
   206→			error: string,
   207→		) => void;
   208→		/** Callback for timeout events */
   209→		onTimeout?: (
   210→			evaluator: string,
   211→			elapsedMs: number,
   212→			timeoutMs: number,
   213→		) => void;
   214→		/** When true, skip evaluators that require existing file content */
   215→		noFileMode?: boolean;
   216→		/** AI provider to use (defaults to claude) */
   217→		provider?: IAIProvider;
   218→		/** Filter evaluators by type */
   219→		evaluatorFilter?: EvaluatorFilter;
   220→		/** Specific evaluator IDs to run (overrides evaluatorFilter when set) */
   221→		selectedEvaluators?: string[];
   222→		/** Timeout per evaluator in milliseconds */
   223→		timeout?: number;
   224→	} = {},
   225→): Promise<EvaluatorResult[]> {
   226→	const {
   227→		verbose = false,
   228→		debug = false,
   229→		debugDir,
   230→		concurrency = 3,
   231→		evaluators = 100,
   232→		baseDir,
   233→		projectContext,
   234→		onProgress,
   235→		onRetry,
   236→		onTimeout,
   237→		noFileMode = false,
   238→		provider = getProvider(),
   239→		evaluatorFilter = "all",
   240→		selectedEvaluators,
   241→		timeout = DEFAULT_TIMEOUT_MS,
   242→	} = options;
   243→
   244→	// Apply filter first, then limit by count
   245→	const allEvaluatorFiles = EVALUATOR_FILES;
   246→	const filteredFiles =
   247→		selectedEvaluators && selectedEvaluators.length > 0
   248→			? filterEvaluatorsByIds(allEvaluatorFiles, selectedEvaluators)
   249→			: filterEvaluatorsByType(allEvaluatorFiles, evaluatorFilter);
   250→	const selectedFiles = filteredFiles.slice(
   251→		0,
   252→		Math.min(evaluators, filteredFiles.length),
   253→	);
   254→	const evaluatorPaths = selectedFiles.map((file) =>
   255→		resolve(EVALUATORS_DIR, file),
   256→	);
   257→
   258→	if (verbose) {
   259→		runnerLogger.log(
   260→			`Running ${evaluatorPaths.length} evaluators (filter: ${evaluatorFilter}, limit: ${evaluators}, concurrency: ${concurrency})`,
   261→		);
   262→	}
   263→
   264→	// Run evaluators with concurrency limit
   265→	const results = await runWithConcurrencyLimit(
   266→		evaluatorPaths,
   267→		concurrency,
   268→		async (evaluatorPath, i) => {
   269→			const evaluatorFilename = selectedFiles[i]!;
   270→			const evaluatorName = evaluatorFilename.replace(".md", "");
   271→
   272→			if (onProgress) {
   273→				onProgress(evaluatorName, i + 1, evaluatorPaths.length);
   274→			}
   275→
   276→			// Check if evaluator should be skipped in no-file mode
   277→			if (noFileMode && !shouldExecuteIfNoFile(evaluatorFilename)) {
   278→				if (verbose) {
   279→					runnerLogger.log(
   280→						`Skipping ${evaluatorName} - requires existing file content`,
   281→					);
   282→				}
   283→				return {
   284→					evaluator: evaluatorName,
   285→					issues: [],
   286→					skipped: true,
   287→					skipReason:
   288→						"No context file exists and this evaluator requires existing content to evaluate",
   289→				};
   290→			}
   291→
   292→			// Check if this evaluator requires file filtering
   293→			if (hasFileFiltering(evaluatorFilename)) {
   294→				const reason = getFilteringReason(evaluatorFilename);
   295→				const filterBaseDir = baseDir || dirname(agentsFilePath);
   296→
   297→				// Apply filtering to determine if this file should be evaluated
   298→				const filteredFiles = filterFilesForEvaluator(
   299→					evaluatorFilename,
   300→					[agentsFilePath],
   301→					filterBaseDir,
   302→				);
   303→
   304→				// If this file was filtered out, return empty result
   305→				if (filteredFiles.length === 0) {
   306→					if (verbose) {
   307→						runnerLogger.log(
   308→							`${evaluatorName} has file filtering enabled: ${reason}`,
   309→						);
   310→						runnerLogger.log(
   311→							`Skipping evaluation for this file (not root-level)`,
   312→						);
   313→					}
   314→					return {
   315→						evaluator: evaluatorName,
   316→						issues: [],
   317→					};
   318→				}
   319→
   320→				if (verbose) {
   321→					runnerLogger.log(
   322→						`${evaluatorName} has file filtering enabled: ${reason}`,
   323→					);
   324→					runnerLogger.log(`File passed filtering, proceeding with evaluation`);
   325→				}
   326→			}
   327→
   328→			try {
   329→				if (verbose) {
   330→					runnerLogger.log(`\n========================================`);
   331→					runnerLogger.log(
   332→						`Starting evaluator ${i + 1}/${evaluatorPaths.length}: ${evaluatorName}`,
   333→					);
   334→					runnerLogger.log(`========================================`);
   335→				}
   336→
   337→				// Read evaluator and AGENTS.md content
   338→				let evaluatorPrompt: string;
   339→				let agentsContent: string;
   340→
   341→				try {
   342→					evaluatorPrompt = await loadEvaluatorPrompt(evaluatorPath);
   343→					agentsContent = noFileMode
   344→						? ""
   345→						: await readFile(agentsFilePath, "utf-8");
   346→				} catch (error) {
   347→					const errorMessage =
   348→						error instanceof Error ? error.message : String(error);
   349→					runnerLogger.error(
   350→						`Failed to read files for ${evaluatorName}:`,
   351→						errorMessage,
   352→					);
   353→					return {
   354→						evaluator: evaluatorName,
   355→						issues: [],
   356→						error: `File read error: ${errorMessage}`,
   357→					};
   358→				}
   359→
   360→				if (verbose) {
   361→					runnerLogger.log(
   362→						`Read evaluator prompt (${evaluatorPrompt.length} chars)`,
   363→					);
   364→					runnerLogger.log(
   365→						`Read AGENTS.md content (${agentsContent.length} chars)`,
   366→					);
   367→				}
   368→
   369→				// Build prompt with project context
   370→				const fullPrompt = await buildSingleFilePrompt(
   371→					evaluatorPrompt,
   372→					agentsContent,
   373→					projectContext,
   374→					evaluatorName,
   375→				);
   376→
   377→				if (verbose) {
   378→					runnerLogger.log(`Built final prompt: ${fullPrompt.length} chars`);
   379→					runnerLogger.log(`Invoking ${provider.displayName}...`);
   380→				}
   381→
   382→				// Save prompt to debug directory if debug mode is enabled
   383→				if (debug && debugDir) {
   384→					const promptFile = resolve(debugDir, `${evaluatorName}-prompt.md`);
   385→					await writeFile(promptFile, fullPrompt, "utf-8");
   386→					if (verbose) {
   387→						const debugLogger = createLogger("Debug");
   388→						debugLogger.log(`Saved prompt to: ${promptFile}`);
   389→					}
   390→				}
   391→
   392→				// NEW: Always log runtime prompt to persistent debug folder (blocking write)
   393→				await logRuntimePrompt({
   394→					evaluatorName,
   395→					prompt: fullPrompt,
   396→					mode: "independent",
   397→					verbose,
   398→				});
   399→
   400→				// Log execution context before invoking AI agent
   401→				runnerLogger.log(
   402→					`[Agent] Executing evaluator: ${evaluatorName} (independent mode)`,
   403→				);
   404→				runnerLogger.log(
   405→					`[Agent] Working directory: ${baseDir || process.cwd()}`,
   406→				);
   407→
   408→				// Invoke provider with retry logic
   409→				const evaluatorStartTime = Date.now();
   410→				const response = await provider.invokeWithRetry(fullPrompt, {
   411→					verbose,
   412→					timeout, // Configurable timeout (default: 10 minutes)
   413→					cwd: baseDir, // Execute in the cloned repository directory
   414→					onRetry: onRetry
   415→						? (event) =>
   416→								onRetry(
   417→									evaluatorName,
   418→									event.attempt,
   419→									event.maxRetries,
   420→									event.error,
   421→								)
   422→						: undefined,
   423→					onTimeout: onTimeout
   424→						? (event) =>
   425→								onTimeout(evaluatorName, event.elapsedMs, event.timeoutMs)
   426→						: undefined,
   427→				});
   428→				const evaluatorDuration = (Date.now() - evaluatorStartTime) / 1000;
   429→
   430→				if (verbose) {
   431→					const evaluatorLogger = createLogger("Evaluator");
   432→					const resultPreview = response.result
   433→						? response.result.substring(0, 1000)
   434→						: "(empty)";
   435→					evaluatorLogger.log(
   436→						`Response type: ${typeof response.result}, length: ${response.result?.length ?? 0}`,
   437→					);
   438→					evaluatorLogger.log(
   439→						`Raw response (first 1000 chars):\n${resultPreview}...`,
   440→					);
   441→				}
   442→
   443→				// Save response to debug directory if debug mode is enabled
   444→				if (debug && debugDir) {
   445→					const responseFile = resolve(
   446→						debugDir,
   447→						`${evaluatorName}-response.json`,
   448→					);
   449→					await writeFile(
   450→						responseFile,
   451→						JSON.stringify(response, null, 2),
   452→						"utf-8",
   453→					);
   454→					if (verbose) {
   455→						const debugLogger = createLogger("Debug");
   456→						debugLogger.log(`Saved response to: ${responseFile}`);
   457→					}
   458→				}
   459→
   460→				// Parse issues from response
   461→				if (verbose) {
   462→					runnerLogger.log(`Parsing response for issues...`);
   463→				}
   464→				const parseResult = parseEvaluatorResult(response.result, verbose);
   465→
   466→				// Add issueType to each issue based on evaluator
   467→				const issueType = getIssueTypeFromEvaluatorName(evaluatorFilename);
   468→				for (const issue of parseResult.issues) {
   469→					issue.issueType = issueType;
   470→				}
   471→
   472→				// Populate snippets from file content
   473→				populateSnippets(parseResult.issues, new Map(), agentsContent);
   474→
   475→				// Enhance parsing errors with evaluator context
   476→				const errors: StructuredError[] = parseResult.errors.map((e) => ({
   477→					...e,
   478→					evaluatorName: evaluatorName,
   479→					filePath: agentsFilePath,
   480→				}));
   481→
   482→				// Always log evaluator completion with timing
   483→				const evalLogger = createLogger(evaluatorName);
   484→				evalLogger.log(`✓ Completed in ${evaluatorDuration.toFixed(1)}s`);
   485→
   486→				if (verbose) {
   487→					runnerLogger.log(`✓ Found ${parseResult.issues.length} issues`);
   488→					if (errors.length > 0) {
   489→						runnerLogger.warn(`⚠️  ${errors.length} parsing error(s) occurred`);
   490→					}
   491→					if (response.usage) {
   492→						runnerLogger.log(formatTokenUsage(response.usage));
   493→						if (response.cost_usd) {
   494→							runnerLogger.log(`Cost: $${response.cost_usd.toFixed(4)}`);
   495→						}
   496→					}
   497→					if (response.duration_ms) {
   498→						runnerLogger.log(
   499→							`API processing time: ${(response.duration_ms / 1000).toFixed(1)}s`,
   500→						);
   501→					}
   502→				}
   503→
   504→				return {
   505→					evaluator: evaluatorName,
   506→					issues: parseResult.issues,
   507→					errors: errors.length > 0 ? errors : undefined,
   508→					usage: response.usage,
   509→					cost_usd: response.cost_usd,
   510→					duration_ms: response.duration_ms,
   511→					finalPrompt: fullPrompt,
   512→				};
   513→			} catch (error) {
   514→				const errorMessage =
   515→					error instanceof Error ? error.message : String(error);
   516→				const isTimeout =
   517→					errorMessage.includes("timeout") || errorMessage.includes("TIMEOUT");
   518→
   519→				// Log with appropriate symbol and timing info
   520→				const evalLogger = createLogger(evaluatorName);
   521→				if (isTimeout) {
   522→					evalLogger.log(`❌ TIMEOUT after ${(timeout / 1000).toFixed(1)}s`);
   523→				} else {
   524→					runnerLogger.error(`\n❌ Evaluator ${evaluatorName} FAILED`);
   525→					runnerLogger.error(`Error: ${errorMessage}\n`);
   526→				}
   527→				if (verbose && error instanceof Error && error.stack) {
   528→					runnerLogger.error(`Stack trace:\n${error.stack}`);
   529→				}
   530→
   531→				// Create structured error
   532→				const structuredError: StructuredError = {
   533→					message: errorMessage,
   534→					category: determineErrorCategory(error),
   535→					severity: "partial",
   536→					evaluatorName: evaluatorName,
   537→					filePath: agentsFilePath,
   538→					timestamp: new Date(),
   539→					retryable: false,
   540→					technicalDetails: error instanceof Error ? error.stack : undefined,
   541→				};
   542→
   543→				return {
   544→					evaluator: evaluatorName,
   545→					issues: [],
   546→					error: errorMessage,
   547→					errors: [structuredError],
   548→				};
   549→			}
   550→		},
   551→	);
   552→
   553→	return results;
   554→}
   555→
   556→/**
   557→ * Aggregate all issues from evaluator results
   558→ */
   559→export function aggregateIssues(results: EvaluatorResult[]): Issue[] {
   560→	return results.flatMap((r) => r.issues);
   561→}
   562→
   563→/**
   564→ * Count issues by severity
   565→ * Thresholds: High (8-10), Medium (6-7), Low (5)
   566→ * Note: Evaluator prompts instruct AI to not report issues with severity ≤4
   567→ */
   568→export function countBySeverity(issues: Issue[]): {
   569→	high: number;
   570→	medium: number;
   571→	low: number;
   572→} {
   573→	return {
   574→		high: issues.filter((i) => getIssueSeverity(i) >= 8).length,
   575→		medium: issues.filter(
   576→			(i) => getIssueSeverity(i) >= 6 && getIssueSeverity(i) < 8,
   577→		).length,
   578→		low: issues.filter((i) => getIssueSeverity(i) < 6).length,
   579→	};
   580→}
   581→
   582→/**
   583→ * Create a summary of evaluation results for a file
   584→ */
   585→export function createFileResult(
   586→	filePath: string,
   587→	relativePath: string,
   588→	evaluations: EvaluatorResult[],
   589→): FileEvaluationResult {
   590→	const allIssues = aggregateIssues(evaluations);
   591→	const counts = countBySeverity(allIssues);
   592→
   593→	// Aggregate token usage and costs
   594→	let totalInputTokens = 0;
   595→	let totalOutputTokens = 0;
   596→	let totalCacheCreation = 0;
   597→	let totalCacheRead = 0;
   598→	let totalCost = 0;
   599→	let totalDuration = 0;
   600→
   601→	for (const evaluation of evaluations) {
   602→		if (evaluation.usage) {
   603→			totalInputTokens += evaluation.usage.input_tokens;
   604→			totalOutputTokens += evaluation.usage.output_tokens;
   605→			totalCacheCreation += evaluation.usage.cache_creation_input_tokens || 0;
   606→			totalCacheRead += evaluation.usage.cache_read_input_tokens || 0;
   607→		}
   608→		if (evaluation.cost_usd) {
   609→			totalCost += evaluation.cost_usd;
   610→		}
   611→		if (evaluation.duration_ms) {
   612→			totalDuration += evaluation.duration_ms;
   613→		}
   614→	}
   615→
   616→	return {
   617→		filePath,
   618→		relativePath,
   619→		evaluations,
   620→		totalIssues: allIssues.length,
   621→		highCount: counts.high,
   622→		mediumCount: counts.medium,
   623→		lowCount: counts.low,
   624→		totalUsage: {
   625→			input_tokens: totalInputTokens,
   626→			output_tokens: totalOutputTokens,
   627→			cache_creation_input_tokens: totalCacheCreation,
   628→			cache_read_input_tokens: totalCacheRead,
   629→		},
   630→		totalCost: totalCost > 0 ? totalCost : undefined,
   631→		totalDuration: totalDuration > 0 ? totalDuration : undefined,
   632→	};
   633→}
