   638→
   639→/**
   640→ * Multi-file context for unified evaluation
   641→ */
   642→export interface MultiFileContext {
   643→	files: FileContext[];
   644→	totalTokenEstimate: number;
   645→}
   646→
   647→/**
   648→ * Result from unified multi-file evaluation
   649→ */
   650→export interface UnifiedEvaluationResult {
   651→	files: Record<string, FileEvaluationResult>;
   652→	crossFileIssues: Issue[];
   653→	evaluatorResults: UnifiedEvaluatorResult[];
   654→	totalUsage?: Usage;
   655→	totalCost?: number;
   656→	totalDuration?: number;
   657→}
   658→
   659→/**
   660→ * Result from a single evaluator in unified mode
   661→ */
   662→export interface UnifiedEvaluatorResult {
   663→	evaluator: string;
   664→	perFileIssues: Record<string, Issue[]>;
   665→	crossFileIssues: Issue[];
   666→	error?: string;
   667→	errors?: StructuredError[]; // Structured error information
   668→	usage?: Usage;
   669→	cost_usd?: number;
   670→	duration_ms?: number;
   671→	finalPrompt?: string;
   672→	/** Whether this evaluator was skipped (e.g., no file mode) */
