   677→
   678→/**
   679→ * Default token limit for unified evaluation (100K tokens to leave room for response)
   680→ */
   681→export const DEFAULT_MAX_UNIFIED_TOKENS = 100000;
   682→
   683→/**
   684→ * Build multi-file context from file paths
   685→ */
   686→export async function buildMultiFileContext(
   687→	filePaths: string[],
   688→	getRelativePath: (path: string) => string,
   689→): Promise<MultiFileContext> {
   690→	const files: FileContext[] = [];
   691→	let totalContent = "";
   692→	const timeout = 30000; // 30 second timeout
   693→
   694→	for (const filePath of filePaths) {
   695→		try {
   696→			const content = await Promise.race([
   697→				readFile(filePath, "utf-8"),
   698→				new Promise<never>((_, reject) =>
   699→					setTimeout(
   700→						() => reject(new Error(`File read timeout after ${timeout}ms`)),
   701→						timeout,
   702→					),
   703→				),
   704→			]);
   705→			const relativePath = getRelativePath(filePath);
   706→			files.push({ filePath, relativePath, content });
   707→			totalContent += content;
   708→		} catch (error) {
   709→			const errorMessage =
   710→				error instanceof Error ? error.message : String(error);
   711→			throw new Error(`Failed to read ${filePath}: ${errorMessage}`);
   712→		}
   713→	}
   714→
   715→	return {
   716→		files,
   717→		totalTokenEstimate: estimateTokens(totalContent),
   718→	};
   719→}
   720→
   721→/**
   722→ * Check if unified evaluation is viable given token limits
   723→ */
   724→export function canUseUnifiedMode(
   725→	context: MultiFileContext,
   726→	maxTokens: number = DEFAULT_MAX_UNIFIED_TOKENS,
   727→): { viable: boolean; reason?: string } {
   728→	if (context.totalTokenEstimate > maxTokens) {
   729→		return {
   730→			viable: false,
   731→			reason: `Combined file content (~${context.totalTokenEstimate} tokens) exceeds limit (${maxTokens} tokens)`,
   732→		};
   733→	}
   734→	return { viable: true };
   735→}
   736→
   737→/**
   738→ * Run all evaluators against multiple context files (AGENTS.md / CLAUDE.md) in unified mode
   739→ */
   740→export async function runUnifiedEvaluation(
   741→	filePaths: string[],
   742→	getRelativePath: (path: string) => string,
   743→	options: {
   744→		verbose?: boolean;
   745→		debug?: boolean;
   746→		debugDir?: string;
   747→		concurrency?: number;
   748→		evaluators?: number;
   749→		maxTokens?: number;
   750→		baseDir?: string;
   751→		projectContext?: string;
   752→		onProgress?: (evaluator: string, index: number, total: number) => void;
   753→		/** Callback for retry events */
   754→		onRetry?: (
   755→			evaluator: string,
   756→			attempt: number,
   757→			maxRetries: number,
   758→			error: string,
   759→		) => void;
   760→		/** Callback for timeout events */
   761→		onTimeout?: (
   762→			evaluator: string,
   763→			elapsedMs: number,
   764→			timeoutMs: number,
   765→		) => void;
   766→		/** When true, skip evaluators that require existing file content */
   767→		noFileMode?: boolean;
   768→		/** AI provider to use (defaults to claude) */
   769→		provider?: IAIProvider;
   770→		/** Filter evaluators by type */
   771→		evaluatorFilter?: EvaluatorFilter;
   772→		/** Specific evaluator IDs to run (overrides evaluatorFilter when set) */
   773→		selectedEvaluators?: string[];
   774→		/** Timeout per evaluator in milliseconds */
   775→		timeout?: number;
   776→	} = {},
   777→): Promise<UnifiedEvaluationResult> {
   778→	const {
   779→		verbose = false,
   780→		debug = false,
   781→		debugDir,
   782→		concurrency = 3,
   783→		evaluators = 100,
   784→		maxTokens = DEFAULT_MAX_UNIFIED_TOKENS,
   785→		baseDir,
   786→		projectContext,
   787→		onProgress,
   788→		onRetry,
   789→		onTimeout,
   790→		noFileMode = false,
   791→		provider = getProvider(),
   792→		evaluatorFilter = "all",
   793→		selectedEvaluators,
   794→		timeout = DEFAULT_TIMEOUT_MS,
   795→	} = options;
   796→
   797→	// Build file context
   798→	const context = await buildMultiFileContext(filePaths, getRelativePath);
   799→
   800→	const unifiedLogger = createLogger("Unified");
   801→	if (verbose) {
   802→		unifiedLogger.log(`Building context for ${context.files.length} files`);
   803→		unifiedLogger.log(`Total estimated tokens: ${context.totalTokenEstimate}`);
   804→	}
   805→
   806→	// Check if unified mode is viable
   807→	const viability = canUseUnifiedMode(context, maxTokens);
   808→	if (!viability.viable) {
   809→		throw new Error(`Cannot use unified mode: ${viability.reason}`);
   810→	}
   811→
   812→	// Apply filter first, then limit by count
   813→	const allEvaluatorFiles = EVALUATOR_FILES;
   814→	const filteredFiles =
   815→		selectedEvaluators && selectedEvaluators.length > 0
   816→			? filterEvaluatorsByIds(allEvaluatorFiles, selectedEvaluators)
   817→			: filterEvaluatorsByType(allEvaluatorFiles, evaluatorFilter);
   818→	const selectedFiles = filteredFiles.slice(
   819→		0,
   820→		Math.min(evaluators, filteredFiles.length),
   821→	);
   822→	const evaluatorPaths = selectedFiles.map((file) =>
   823→		resolve(EVALUATORS_DIR, file),
   824→	);
   825→
   826→	if (verbose) {
   827→		unifiedLogger.log(
   828→			`Running ${evaluatorPaths.length} evaluators (filter: ${evaluatorFilter}, limit: ${evaluators}, concurrency: ${concurrency})`,
   829→		);
   830→	}
   831→
   832→	// Run evaluators with concurrency limit
   833→	const evaluatorResults: UnifiedEvaluatorResult[] =
   834→		await runWithConcurrencyLimit(
   835→			evaluatorPaths,
   836→			concurrency,
   837→			async (evaluatorPath, i) => {
   838→				const evaluatorFilename = selectedFiles[i]!;
   839→				const evaluatorName = evaluatorFilename.replace(".md", "");
   840→
   841→				if (onProgress) {
   842→					onProgress(evaluatorName, i + 1, evaluatorPaths.length);
   843→				}
   844→
   845→				// Check if evaluator should be skipped in no-file mode
   846→				if (noFileMode && !shouldExecuteIfNoFile(evaluatorFilename)) {
   847→					if (verbose) {
   848→						unifiedLogger.log(
   849→							`Skipping ${evaluatorName} - requires existing file content`,
   850→						);
   851→					}
   852→					// Initialize empty per-file issues for skipped evaluator
   853→					const perFileIssues: Record<string, Issue[]> = {};
   854→					for (const file of context.files) {
   855→						perFileIssues[file.relativePath] = [];
   856→					}
   857→					return {
   858→						evaluator: evaluatorName,
   859→						perFileIssues,
   860→						crossFileIssues: [],
   861→						skipped: true,
   862→						skipReason:
   863→							"No context file exists and this evaluator requires existing content to evaluate",
   864→					};
   865→				}
   866→
   867→				// Apply file filtering for this evaluator
   868→				const filterBaseDir =
   869→					filePaths.length > 0 && filePaths[0]
   870→						? dirname(filePaths[0])
   871→						: process.cwd();
   872→				const filteredPaths = filterFilesForEvaluator(
   873→					evaluatorFilename,
   874→					filePaths,
   875→					filterBaseDir,
   876→				);
   877→
   878→				// Log filtering if verbose
   879→				if (verbose && hasFileFiltering(evaluatorFilename)) {
   880→					const reason = getFilteringReason(evaluatorFilename);
   881→					unifiedLogger.log(
   882→						`${evaluatorName}: Filtering ${filePaths.length} → ${filteredPaths.length} files`,
   883→					);
   884→					unifiedLogger.log(`Reason: ${reason}`);
   885→					unifiedLogger.log(
   886→						`Files: ${filteredPaths.map((f) => getRelativePath(f)).join(", ")}`,
   887→					);
   888→				}
   889→
   890→				// Build filtered file context for this evaluator
   891→				const filteredContext = await buildMultiFileContext(
   892→					filteredPaths,
   893→					getRelativePath,
   894→				);
   895→
   896→				try {
   897→					// Read evaluator prompt
   898→					const evaluatorPrompt = await loadEvaluatorPrompt(evaluatorPath);
   899→
   900→					// Build multi-file prompt with project context
   901→					const fullPrompt = await buildMultiFilePrompt(
   902→						evaluatorPrompt,
   903→						filteredContext.files,
   904→						projectContext,
   905→						evaluatorName,
   906→					);
   907→					const tokenEstimate = estimateTokens(fullPrompt);
   908→
   909→					if (verbose) {
   910→						const evaluatorLogger = createLogger("Evaluator");
   911→						evaluatorLogger.log(
   912→							`Running multi-file evaluation: ${evaluatorPath}`,
   913→						);
   914→						evaluatorLogger.log(
   915→							`Files: ${filteredContext.files.map((f) => f.relativePath).join(", ")}`,
   916→						);
   917→						evaluatorLogger.log(
   918→							`Prompt length: ${fullPrompt.length} chars (~${tokenEstimate} tokens)`,
   919→						);
   920→					}
   921→
   922→					// Save prompt to debug directory if debug mode is enabled
   923→					if (debug && debugDir) {
   924→						const promptFile = resolve(
   925→							debugDir,
   926→							`${evaluatorName}-unified-prompt.md`,
   927→						);
   928→						await writeFile(promptFile, fullPrompt, "utf-8");
   929→						if (verbose) {
   930→							const debugLogger = createLogger("Debug");
   931→							debugLogger.log(`Saved unified prompt to: ${promptFile}`);
   932→						}
   933→					}
   934→
   935→					// NEW: Always log runtime prompt to persistent debug folder (blocking write)
   936→					await logRuntimePrompt({
   937→						evaluatorName,
   938→						prompt: fullPrompt,
   939→						mode: "unified",
   940→						verbose,
   941→					});
   942→
   943→					// Log execution context before invoking AI agent
   944→					runnerLogger.log(
   945→						`[Agent] Executing evaluator: ${evaluatorName} (unified mode)`,
   946→					);
   947→					runnerLogger.log(
   948→						`[Agent] Working directory: ${baseDir || process.cwd()}`,
   949→					);
   950→
   951→					// Invoke provider with retry logic
   952→					const evaluatorStartTime = Date.now();
   953→					const response = await provider.invokeWithRetry(fullPrompt, {
   954→						verbose,
   955→						timeout, // Configurable timeout (default: 10 minutes)
   956→						cwd: baseDir, // Execute in the cloned repository directory
   957→						onRetry: onRetry
   958→							? (event) =>
   959→									onRetry(
   960→										evaluatorName,
   961→										event.attempt,
   962→										event.maxRetries,
   963→										event.error,
   964→									)
   965→							: undefined,
   966→						onTimeout: onTimeout
   967→							? (event) =>
   968→									onTimeout(evaluatorName, event.elapsedMs, event.timeoutMs)
   969→							: undefined,
   970→					});
   971→					const evaluatorDuration = (Date.now() - evaluatorStartTime) / 1000;
   972→
   973→					if (verbose) {
   974→						unifiedLogger.log(`\n✓ Received response from provider`);
   975→						unifiedLogger.log(
   976→							`Response type: ${typeof response.result}, length: ${response.result?.length ?? 0}`,
   977→						);
   978→						const resultPreview = response.result
   979→							? response.result.substring(0, 500)
   980→							: "(empty)";
   981→						unifiedLogger.log(
   982→							`Response preview (first 500 chars):\n${resultPreview}...`,
   983→						);
   984→					}
   985→
   986→					// Save response to debug directory if debug mode is enabled
   987→					if (debug && debugDir) {
   988→						const responseFile = resolve(
   989→							debugDir,
   990→							`${evaluatorName}-unified-response.json`,
   991→						);
   992→						await writeFile(
   993→							responseFile,
   994→							JSON.stringify(response, null, 2),
   995→							"utf-8",
   996→						);
   997→						if (verbose) {
   998→							const debugLogger = createLogger("Debug");
   999→							debugLogger.log(`Saved unified response to: ${responseFile}`);
  1000→						}
  1001→					}
  1002→
  1003→					// Parse the JSON array from the result
  1004→					const parseResult = parseEvaluatorResult(response.result, verbose);
  1005→
  1006→					// Add issueType to each issue based on evaluator
  1007→					const issueType = getIssueTypeFromEvaluatorName(evaluatorFilename);
  1008→					for (const issue of parseResult.issues) {
  1009→						issue.issueType = issueType;
  1010→					}
  1011→
  1012→					// Enhance parsing errors with evaluator context
  1013→					const errors: StructuredError[] = parseResult.errors.map((e) => ({
  1014→						...e,
  1015→						evaluatorName: evaluatorName,
  1016→					}));
  1017→
  1018→					const contentMap = new Map<string, string>();
  1019→					const basenameMap = new Map<string, string[]>(); // Track basenames to detect duplicates
  1020→
  1021→					for (const file of filteredContext.files) {
  1022→						contentMap.set(file.relativePath, file.content);
  1023→
  1024→						// Track basenames to detect duplicates
  1025→						const filename = file.relativePath.split("/").pop();
  1026→						if (filename) {
  1027→							if (!basenameMap.has(filename)) {
  1028→								basenameMap.set(filename, []);
  1029→							}
  1030→							basenameMap.get(filename)!.push(file.relativePath);
  1031→						}
  1032→					}
  1033→
  1034→					// Warn about duplicate basenames (informational)
  1035→					if (verbose) {
  1036→						for (const [basename, fullPaths] of basenameMap) {
  1037→							if (fullPaths.length > 1) {
  1038→								const hasRootLevel = fullPaths.some((p) => !p.includes("/"));
  1039→								runnerLogger.warn(
  1040→									`ℹ️  Info: Multiple files with basename "${basename}":`,
  1041→								);
  1042→								for (const path of fullPaths) {
  1043→									const marker = !path.includes("/") ? " (default)" : "";
  1044→									runnerLogger.warn(`    - ${path}${marker}`);
  1045→								}
  1046→								if (hasRootLevel) {
  1047→									runnerLogger.warn(
  1048→										`Basename-only references (e.g., "${basename}") will use root-level file`,
  1049→									);
  1050→								} else {
  1051→									runnerLogger.warn(
  1052→										`⚠️  No root-level file found - evaluators MUST use full relative paths`,
  1053→									);
  1054→								}
  1055→							}
  1056→						}
  1057→					}
  1058→
  1059→					// Use first AGENTS.md or CLAUDE.md file content as fallback
  1060→					const defaultContent = filteredContext.files.find(
  1061→						(f) =>
  1062→							f.relativePath.includes("AGENTS.md") ||
  1063→							f.relativePath.includes("CLAUDE.md"),
  1064→					)?.content;
  1065→
  1066→					// Populate snippets from file content
  1067→					populateSnippets(parseResult.issues, contentMap, defaultContent);
  1068→
  1069→					// Also populate cross-file snippets
  1070→					populateCrossFileSnippets(parseResult.issues, contentMap);
  1071→
  1072→					// Separate per-file and cross-file issues
  1073→					const { perFileIssues, crossFileIssues } = separateIssuesByType(
  1074→						parseResult.issues,
  1075→						filteredContext.files,
  1076→					);
  1077→
  1078→					// Convert Map to Record for serialization
  1079→					const perFileIssuesRecord: Record<string, Issue[]> = {};
  1080→					for (const [path, issues] of perFileIssues) {
  1081→						perFileIssuesRecord[path] = issues;
  1082→					}
  1083→
  1084→					// Always log evaluator completion with timing
  1085→					const evalLogger = createLogger(evaluatorName);
  1086→					evalLogger.log(`✓ Completed in ${evaluatorDuration.toFixed(1)}s`);
  1087→
  1088→					if (verbose) {
  1089→						const evaluatorLogger = createLogger("Evaluator");
  1090→						const totalPerFile = Array.from(perFileIssues.values()).reduce(
  1091→							(sum, arr) => sum + arr.length,
  1092→							0,
  1093→						);
  1094→						evaluatorLogger.log(
  1095→							`Found ${totalPerFile} per-file issues and ${crossFileIssues.length} cross-file issues`,
  1096→						);
  1097→						if (errors.length > 0) {
  1098→							evaluatorLogger.warn(
  1099→								`⚠️  ${errors.length} parsing error(s) occurred`,
  1100→							);
  1101→						}
  1102→						if (response.usage) {
  1103→							evaluatorLogger.log(formatTokenUsage(response.usage));
  1104→						}
  1105→					}
  1106→
  1107→					return {
  1108→						evaluator: evaluatorName,
  1109→						perFileIssues: perFileIssuesRecord,
  1110→						crossFileIssues,
  1111→						errors: errors.length > 0 ? errors : undefined,
  1112→						usage: response.usage,
  1113→						cost_usd: response.cost_usd,
  1114→						duration_ms: response.duration_ms,
  1115→						finalPrompt: fullPrompt,
  1116→					};
  1117→				} catch (error) {
  1118→					const errorMessage =
  1119→						error instanceof Error ? error.message : String(error);
  1120→					const isTimeout =
  1121→						errorMessage.includes("timeout") ||
  1122→						errorMessage.includes("TIMEOUT");
  1123→
  1124→					// Log with appropriate symbol and timing info
  1125→					const evalLogger = createLogger(evaluatorName);
  1126→					if (isTimeout) {
  1127→						evalLogger.log(`❌ TIMEOUT after ${(timeout / 1000).toFixed(1)}s`);
  1128→					} else if (verbose) {
  1129→						unifiedLogger.error(
  1130→							`Evaluator ${evaluatorName} failed: ${errorMessage}`,
  1131→						);
  1132→					}
  1133→
  1134→					// Create structured error
  1135→					const structuredError: StructuredError = {
  1136→						message: errorMessage,
  1137→						category: determineErrorCategory(error),
  1138→						severity: "partial",
  1139→						evaluatorName: evaluatorName,
  1140→						timestamp: new Date(),
  1141→						retryable: false,
  1142→						technicalDetails: error instanceof Error ? error.stack : undefined,
  1143→					};
  1144→
  1145→					// Initialize empty per-file issues
  1146→					const perFileIssues: Record<string, Issue[]> = {};
  1147→					for (const file of context.files) {
  1148→						perFileIssues[file.relativePath] = [];
  1149→					}
  1150→
  1151→					return {
  1152→						evaluator: evaluatorName,
  1153→						perFileIssues,
  1154→						crossFileIssues: [],
  1155→						error: errorMessage,
