  1157→					};
  1158→				}
  1159→			},
  1160→		);
  1161→
  1162→	// Aggregate results by file and collect cross-file issues
  1163→	const fileResults: Record<string, FileEvaluationResult> = {};
  1164→	const allCrossFileIssues: Issue[] = [];
  1165→	let totalInputTokens = 0;
